CREATE TABLE collection_links(id TEXT PRIMARY KEY,tenant_id TEXT NOT NULL,obligation_id TEXT NOT NULL REFERENCES financial_obligations(id),token_sha256 TEXT NOT NULL UNIQUE,bank_name TEXT NOT NULL,account_type TEXT NOT NULL,account_number_masked TEXT NOT NULL,account_holder TEXT NOT NULL,expires_at TEXT NOT NULL,revoked_at TEXT,created_at TEXT NOT NULL);
CREATE TABLE payment_proofs(id TEXT PRIMARY KEY,tenant_id TEXT NOT NULL,collection_link_id TEXT NOT NULL REFERENCES collection_links(id),file_name TEXT NOT NULL,mime_type TEXT NOT NULL,content_sha256 TEXT NOT NULL,content BLOB NOT NULL,declared_amount INTEGER NOT NULL CHECK(declared_amount>0),payer_note TEXT,uploaded_at TEXT NOT NULL,UNIQUE(collection_link_id,content_sha256));
